// Find the 'Google Drive' knowledge base or flag for creation
const kbList = $input.first().json;
const items = Array.isArray(kbList) ? kbList : (kbList.data || kbList.items || []);
const googleDriveKB = items.find(kb => kb.name === 'Google Drive');

if (googleDriveKB) {
  return [{ json: { kb_id: googleDriveKB.id, kb_exists: true } }];
} else {
  return [{ json: { kb_id: null, kb_exists: false } }];
}

// Merge KB ID from either path (existing or newly created)
const items = $input.all();
const data = items[0].json;
let kb_id = data.kb_id || data.id;
if (!kb_id) {
  throw new Error('Failed to find or create Google Drive knowledge base');
}
return [{ json: { kb_id } }];

// Filter supported file types, determine export format, and detect edits
const trigger = $('Google Drive Trigger').first().json;
const mimeType = trigger.mimeType || '';
const fileName = trigger.name || 'unknown';
const fileId = trigger.id || '';
const lastModified = trigger.modifiedTime || trigger.modifiedDate || new Date().toISOString();

// Google Workspace MIME types -> export format
const exportMap = {
  'application/vnd.google-apps.spreadsheet': { export: 'text/csv', ext: 'csv', type: 'sheets' },
  'application/vnd.google-apps.document': { export: 'text/html', ext: 'html', type: 'docs' },
  'application/vnd.google-apps.presentation': { export: 'text/plain', ext: 'txt', type: 'slides' }
};

// Direct download types
const directTypes = ['application/pdf'];

// Skip unsupported types
const skipPrefixes = ['image/', 'video/', 'audio/', 'application/zip', 'application/x-rar', 'application/x-7z', 'application/gzip'];
const shouldSkip = skipPrefixes.some(p => mimeType.startsWith(p));

if (shouldSkip || !mimeType) {
  return [{ json: { skip: true, reason: 'Unsupported type: ' + mimeType, fileName } }];
}

const exportInfo = exportMap[mimeType];
const isDirect = directTypes.includes(mimeType);

if (!exportInfo && !isDirect) {
  return [{ json: { skip: true, reason: 'Unknown type: ' + mimeType, fileName } }];
}

// Check if file was previously ingested (edit detection)
const staticData = $getWorkflowStaticData('global');
const existingFile = staticData.files ? staticData.files[fileId] : null;
const isEdit = !!existingFile;
const previousOpenWebUIFileId = existingFile ? existingFile.openwebui_file_id : null;

const kb_id = $('Merge KB ID').first().json.kb_id;

return [{ json: {
  skip: false,
  fileId,
  fileName,
  mimeType,
  lastModified,
  isGoogleWorkspace: !!exportInfo,
  isDirect,
  exportMime: exportInfo ? exportInfo.export : null,
  fileType: exportInfo ? exportInfo.type : 'pdf',
  kb_id,
  isEdit,
  previousOpenWebUIFileId
} }];

// Convert file content to Markdown based on file type
const filterData = $('Filter File Type').first().json;
const fileType = filterData.fileType;
const fileName = filterData.fileName;
const fileId = filterData.fileId;
const kb_id = filterData.kb_id;
const isEdit = filterData.isEdit;
const lastModified = filterData.lastModified;
const now = new Date().toISOString();

// Get downloaded content - binary data from Google Drive node
let content = '';
const inputItem = $input.first();
if (inputItem.binary && inputItem.binary.data) {
  // For non-PDF files, read the binary as text
  if (fileType !== 'pdf') {
    content = Buffer.from(inputItem.binary.data.data, 'base64').toString('utf-8');
  }
} else if (inputItem.json && inputItem.json.data) {
  content = inputItem.json.data;
} else if (typeof inputItem.json === 'string') {
  content = inputItem.json;
}

let markdown = '';

if (fileType === 'sheets') {
  // CSV -> Markdown table
  const lines = content.split('\n').filter(l => l.trim());
  if (lines.length > 0) {
    markdown = '# ' + fileName + '\n\n';
    markdown += '**Source:** Google Drive / AI Knowledge\n';
    markdown += '**Last modified:** ' + (lastModified || now).split('T')[0] + '\n\n';

    const headers = lines[0].split(',').map(h => h.replace(/^"|"$/g, '').trim());
    markdown += '| ' + headers.join(' | ') + ' |\n';
    markdown += '| ' + headers.map(() => '---').join(' | ') + ' |\n';

    for (let i = 1; i < lines.length; i++) {
      // Handle CSV with quoted fields containing commas
      const row = [];
      let inQuote = false;
      let field = '';
      for (const char of lines[i]) {
        if (char === '"') { inQuote = !inQuote; }
        else if (char === ',' && !inQuote) { row.push(field.trim()); field = ''; }
        else { field += char; }
      }
      row.push(field.trim());
      markdown += '| ' + row.join(' | ') + ' |\n';
    }
  }
} else if (fileType === 'docs') {
  // HTML -> Markdown
  markdown = '# ' + fileName + '\n\n';
  markdown += '**Source:** Google Drive / AI Knowledge\n';
  markdown += '**Last modified:** ' + (lastModified || now).split('T')[0] + '\n\n';

  let text = content;
  // Convert headings
  text = text.replace(/<h1[^>]*>(.*?)<\/h1>/gi, '# $1\n\n');
  text = text.replace(/<h2[^>]*>(.*?)<\/h2>/gi, '## $1\n\n');
  text = text.replace(/<h3[^>]*>(.*?)<\/h3>/gi, '### $1\n\n');
  text = text.replace(/<h4[^>]*>(.*?)<\/h4>/gi, '#### $1\n\n');
  // Convert formatting
  text = text.replace(/<b[^>]*>(.*?)<\/b>/gi, '**$1**');
  text = text.replace(/<strong[^>]*>(.*?)<\/strong>/gi, '**$1**');
  text = text.replace(/<i[^>]*>(.*?)<\/i>/gi, '*$1*');
  text = text.replace(/<em[^>]*>(.*?)<\/em>/gi, '*$1*');
  // Convert links
  text = text.replace(/<a[^>]*href="([^"]*?)"[^>]*>(.*?)<\/a>/gi, '[$2]($1)');
  // Convert lists
  text = text.replace(/<li[^>]*>(.*?)<\/li>/gi, '- $1\n');
  // Convert paragraphs
  text = text.replace(/<p[^>]*>(.*?)<\/p>/gi, '$1\n\n');
  // Convert line breaks
  text = text.replace(/<br\s*\/?>/gi, '\n');
  // Strip remaining HTML tags
  text = text.replace(/<[^>]+>/g, '');
  // Decode common HTML entities
  text = text.replace(/&amp;/g, '&').replace(/&lt;/g, '<').replace(/&gt;/g, '>').replace(/&quot;/g, '"').replace(/&#39;/g, "'").replace(/&nbsp;/g, ' ');
  // Clean up whitespace
  text = text.replace(/\n{3,}/g, '\n\n').trim();

  markdown += text;
} else if (fileType === 'slides') {
  // Plain text -> Markdown with slide separators
  markdown = '# ' + fileName + '\n\n';
  markdown += '**Source:** Google Drive / AI Knowledge\n';
  markdown += '**Last modified:** ' + (lastModified || now).split('T')[0] + '\n\n';

  // Split by common slide separators (form feed, or "Slide N" headers)
  const slides = content.split(/\n(?=Slide \d|\f)/i);
  slides.forEach((slide, i) => {
    const trimmed = slide.trim();
    if (trimmed) {
      markdown += '## Slide ' + (i + 1) + '\n\n' + trimmed + '\n\n---\n\n';
    }
  });
} else if (fileType === 'pdf') {
  // PDF: pass through as-is, OpenWebUI handles extraction
  markdown = null;
}

const outputFileName = fileName.replace(/\.[^/.]+$/, '') + (markdown ? '.md' : '.pdf');

// Create binary output for upload
const output = { json: {
  markdown,
  fileName: outputFileName,
  originalName: fileName,
  fileId,
  fileType,
  kb_id,
  isEdit,
  isPdf: fileType === 'pdf'
}, binary: {} };

if (markdown) {
  // Convert markdown text to binary for file upload
  output.binary.data = {
    data: Buffer.from(markdown, 'utf-8').toString('base64'),
    mimeType: 'text/markdown',
    fileName: outputFileName
  };
} else if (fileType === 'pdf' && inputItem.binary && inputItem.binary.data) {
  // Pass through PDF binary as-is
  output.binary.data = inputItem.binary.data;
  output.binary.data.fileName = outputFileName;
}

return [output];

// Save file mapping to workflow static data
const staticData = $getWorkflowStaticData('global');
if (!staticData.files) staticData.files = {};

const gdriveId = $('Filter File Type').first().json.fileId;
const openwebuiFileId = $('Upload to OpenWebUI').first().json.id;
const fileName = $('Filter File Type').first().json.fileName;
const isEdit = $('Filter File Type').first().json.isEdit;

staticData.files[gdriveId] = {
  openwebui_file_id: openwebuiFileId,
  filename: fileName,
  last_modified: new Date().toISOString()
};

return [{ json: {
  saved: true,
  gdrive_id: gdriveId,
  openwebui_file_id: openwebuiFileId,
  filename: fileName,
  isEdit
} }];

// Check for deleted files by looking up the triggered file in static data
// The Google Drive Trigger fires for file changes including deletions
// When a file is trashed/deleted, we detect it here
const staticData = $getWorkflowStaticData('global');
if (!staticData.files || Object.keys(staticData.files).length === 0) {
  return [{ json: { hasDelete: false, reason: 'No tracked files' } }];
}

const trigger = $('Google Drive Trigger').first().json;
const fileId = trigger.id || '';
const trashed = trigger.trashed || false;
const trackedFile = staticData.files[fileId];

// If the file is trashed and we have it tracked, it's a deletion
if (trashed && trackedFile) {
  const kb_id = $('Merge KB ID').first().json.kb_id;
  return [{ json: {
    hasDelete: true,
    gdriveId: fileId,
    openwebui_file_id: trackedFile.openwebui_file_id,
    filename: trackedFile.filename,
    kb_id
  } }];
}

return [{ json: { hasDelete: false, reason: 'File not tracked or not trashed' } }];

// Remove deleted file from static data tracking
const staticData = $getWorkflowStaticData('global');
const gdriveId = $('Check Deletions').first().json.gdriveId;
const fileName = staticData.files[gdriveId] ? staticData.files[gdriveId].filename : 'unknown';
delete staticData.files[gdriveId];
return [{ json: { deleted: true, filename: fileName, gdriveId } }];
